import numpy as np

def fk_2link(theta1, theta2, L1=0.3, L2=0.25):
    x = L1*np.cos(theta1) + L2*np.cos(theta1 + theta2)
    y = L1*np.sin(theta1) + L2*np.sin(theta1 + theta2)
    return np.array([x, y])

print(fk_2link(np.pi/4, np.pi/3))   # → [0.073, 0.473]

#include <Eigen/Geometry>
#include <vector>

using Eigen::Affine3d;
using Eigen::AngleAxisd;
using Eigen::Vector3d;

struct DhParam { double a, alpha, d, theta; };

// FK by chain of homogeneous transforms.
Affine3d fk_dh(const std::vector<DhParam>& dh, const std::vector<double>& q) {
  Affine3d T = Affine3d::Identity();
  for (size_t i = 0; i < dh.size(); ++i) {
    const auto& p = dh[i];
    const double th = p.theta + q[i];
    Affine3d Tz = Affine3d::Identity();
    Tz.translation() = Vector3d(0, 0, p.d);
    Tz.rotate(AngleAxisd(th, Vector3d::UnitZ()));
    Affine3d Tx = Affine3d::Identity();
    Tx.translation() = Vector3d(p.a, 0, 0);
    Tx.rotate(AngleAxisd(p.alpha, Vector3d::UnitX()));
    T = T * Tz * Tx;
  }
  return T;
}

